-- Migration 0013: seed cultural_origins for 17 priority Compass regions
  -- Adds origin records for: JP, DE, FR, IT, BE, CH, SG, IN, MX, BR, ES, CO, AE, US, NL, PT, ZA
  -- (GB, CN, CA were seeded in migration 0008.)
  -- Idempotent re-runs are safe: a duplicate guard on (region_code, tradition) prevents double-insert.

  CREATE UNIQUE INDEX IF NOT EXISTS co_region_tradition_unique
    ON cultural_origins (region_code, tradition);

  -- ── JAPAN ────────────────────────────────────────────────────────
ON CONFLICT (region_code, tradition) DO NOTHING;

